export const FINANCE_DICT_BY_ID = Object.fromEntries(
  FINANCE_DICTIONARY.map(e => [e.id, e])
) as Record<string, FinanceDictEntry>

export const FINANCE_DICT_BY_CATEGORY = FINANCE_DICTIONARY.reduce<Record<string, FinanceDictEntry[]>>(
  (acc, entry) => {
    if (!acc[entry.category]) acc[entry.category] = []
    acc[entry.category].push(entry)
    return acc
  },
  {}
)
